const agentOutput = $input.first().json.output;

// agentOutput empty නම් error වළකන්න
if (!agentOutput) {
  return [{ json: { reply: "Sorry, I couldn't generate a response. Please try again.", isHtml: false } }];
}

let replyContent = agentOutput; // default — plain text
let isHtml = false;

// JSON block එකක් තියෙනවාද check කරනවා
const jsonMatch = agentOutput.match(/\{[\s\S]*\}/);

if (jsonMatch) {
  try {
    const data = JSON.parse(jsonMatch[0]);

    if (data.type === "study_plan") {
      isHtml = true;

      let tableRows = '';
      data.weekly_plan.forEach(day => {
        day.sessions.forEach((session, i) => {
          tableRows += `
            <tr>
              ${i === 0 ? `<td rowspan="${day.sessions.length}" style="font-weight:bold;background:#f0f4ff;padding:8px;border:1px solid #ddd;">${day.day}</td>` : ''}
              <td style="padding:8px;border:1px solid #ddd;">${session.time}</td>
              <td style="padding:8px;border:1px solid #ddd;">${session.subject}</td>
              <td style="padding:8px;border:1px solid #ddd;">${session.topic}</td>
              <td style="padding:8px;border:1px solid #ddd;">${session.technique}</td>
            </tr>`;
        });
      });

      let topicRows = data.topics.map(t => `
        <tr>
          <td style="padding:8px;border:1px solid #ddd;">${t.topic}</td>
          <td style="padding:8px;border:1px solid #ddd;">${t.weeks} weeks</td>
          <td style="padding:8px;border:1px solid #ddd;color:${t.priority==='High'?'red':t.priority==='Medium'?'orange':'green'}">${t.priority}</td>
        </tr>`).join('');

      let tipsList = data.tips.map(t => `<li style="margin:4px 0;">✅ ${t}</li>`).join('');

      replyContent = `
        <div style="font-family:sans-serif;">
          <h2 style="color:#4f46e5;">📚 ${data.subject} Study Plan</h2>
          <p>🎯 Level: <strong>${data.level}</strong></p>
          <h3 style="color:#4f46e5;">📅 Weekly Timetable</h3>
          <table style="width:100%;border-collapse:collapse;margin-bottom:16px;">
            <thead>
              <tr style="background:#4f46e5;color:white;">
                <th style="padding:8px;">Day</th>
                <th style="padding:8px;">Time</th>
                <th style="padding:8px;">Subject</th>
                <th style="padding:8px;">Topic</th>
                <th style="padding:8px;">Technique</th>
              </tr>
            </thead>
            <tbody>${tableRows}</tbody>
          </table>
          <h3 style="color:#4f46e5;">📊 Topic Priority</h3>
          <table style="width:100%;border-collapse:collapse;margin-bottom:16px;">
            <thead>
              <tr style="background:#4f46e5;color:white;">
                <th style="padding:8px;">Topic</th>
                <th style="padding:8px;">Duration</th>
                <th style="padding:8px;">Priority</th>
              </tr>
            </thead>
            <tbody>${topicRows}</tbody>
          </table>
          <h3 style="color:#4f46e5;">💡 Study Tips</h3>
          <ul style="background:#f9f9ff;padding:16px;border-radius:8px;">${tipsList}</ul>
        </div>`;
    }
    // study_plan නෙමෙයි නම් replyContent = agentOutput (plain text)
  } catch (e) {
    // JSON parse fail — replyContent = agentOutput (plain text)
  }
}

// ✅ සෑම විටම reply key එකෙන් return කරනවා
return [{ json: { reply: replyContent, isHtml: isHtml } }];
